# DriverError
# We want to define each variant as a nested class that's also a subclass,
# which is tricky in Python.  To accomplish this we're going to create each
# class separately, then manually add the child classes to the base class's
# __dict__.  All of this happens in dummy class to avoid polluting the module
# namespace.
class DriverError(Exception):
    pass

_UniffiTempDriverError = DriverError

class DriverError:  # type: ignore

    class Configuration(_UniffiTempDriverError):

        def __init__(self, reason):
            super().__init__(", ".join([
                "reason={!r}".format(reason),
            ]))
            self.reason = reason

        def __repr__(self):
            return "DriverError.Configuration({})".format(str(self))
    _UniffiTempDriverError.Configuration = Configuration # type: ignore
    class InvalidArguments(_UniffiTempDriverError):

        def __init__(self, tool, reason):
            super().__init__(", ".join([
                "tool={!r}".format(tool),
                "reason={!r}".format(reason),
            ]))
            self.tool = tool
            self.reason = reason

        def __repr__(self):
            return "DriverError.InvalidArguments({})".format(str(self))
    _UniffiTempDriverError.InvalidArguments = InvalidArguments # type: ignore
    class Transport(_UniffiTempDriverError):

        def __init__(self, socket_path, reason):
            super().__init__(", ".join([
                "socket_path={!r}".format(socket_path),
                "reason={!r}".format(reason),
            ]))
            self.socket_path = socket_path
            self.reason = reason

        def __repr__(self):
            return "DriverError.Transport({})".format(str(self))
    _UniffiTempDriverError.Transport = Transport # type: ignore
    class Protocol(_UniffiTempDriverError):

        def __init__(self, reason):
            super().__init__(", ".join([
                "reason={!r}".format(reason),
            ]))
            self.reason = reason

        def __repr__(self):
            return "DriverError.Protocol({})".format(str(self))
    _UniffiTempDriverError.Protocol = Protocol # type: ignore
    class Tool(_UniffiTempDriverError):

        def __init__(self, tool, message, error_code):
            super().__init__(", ".join([
                "tool={!r}".format(tool),
                "message={!r}".format(message),
                "error_code={!r}".format(error_code),
            ]))
            self.tool = tool
            self.message = message
            self.error_code = error_code

        def __repr__(self):
            return "DriverError.Tool({})".format(str(self))
    _UniffiTempDriverError.Tool = Tool # type: ignore
    class Shutdown(_UniffiTempDriverError):

        def __init__(self):
            pass

        def __repr__(self):
            return "DriverError.Shutdown({})".format(str(self))
    _UniffiTempDriverError.Shutdown = Shutdown # type: ignore

DriverError = _UniffiTempDriverError # type: ignore
del _UniffiTempDriverError


class _UniffiFfiConverterTypeDriverError(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        variant = buf.read_i32()
        if variant == 1:
            return DriverError.Configuration(
                _UniffiFfiConverterString.read(buf),
            )
        if variant == 2:
            return DriverError.InvalidArguments(
                _UniffiFfiConverterString.read(buf),
                _UniffiFfiConverterString.read(buf),
            )
        if variant == 3:
            return DriverError.Transport(
                _UniffiFfiConverterString.read(buf),
                _UniffiFfiConverterString.read(buf),
            )
        if variant == 4:
            return DriverError.Protocol(
                _UniffiFfiConverterString.read(buf),
            )
        if variant == 5:
            return DriverError.Tool(
                _UniffiFfiConverterString.read(buf),
                _UniffiFfiConverterString.read(buf),
                _UniffiFfiConverterString.read(buf),
            )
        if variant == 6:
            return DriverError.Shutdown(
            )
        raise InternalError("Raw enum value doesn't match any cases")

    @staticmethod
    def check_lower(value):
        if isinstance(value, DriverError.Configuration):
            _UniffiFfiConverterString.check_lower(value.reason)
            return
        if isinstance(value, DriverError.InvalidArguments):
            _UniffiFfiConverterString.check_lower(value.tool)
            _UniffiFfiConverterString.check_lower(value.reason)
            return
        if isinstance(value, DriverError.Transport):
            _UniffiFfiConverterString.check_lower(value.socket_path)
            _UniffiFfiConverterString.check_lower(value.reason)
            return
        if isinstance(value, DriverError.Protocol):
            _UniffiFfiConverterString.check_lower(value.reason)
            return
        if isinstance(value, DriverError.Tool):
            _UniffiFfiConverterString.check_lower(value.tool)
            _UniffiFfiConverterString.check_lower(value.message)
            _UniffiFfiConverterString.check_lower(value.error_code)
            return
        if isinstance(value, DriverError.Shutdown):
            return

    @staticmethod
    def write(value, buf):
        if isinstance(value, DriverError.Configuration):
            buf.write_i32(1)
            _UniffiFfiConverterString.write(value.reason, buf)
        if isinstance(value, DriverError.InvalidArguments):
            buf.write_i32(2)
            _UniffiFfiConverterString.write(value.tool, buf)
            _UniffiFfiConverterString.write(value.reason, buf)
        if isinstance(value, DriverError.Transport):
            buf.write_i32(3)
            _UniffiFfiConverterString.write(value.socket_path, buf)
            _UniffiFfiConverterString.write(value.reason, buf)
        if isinstance(value, DriverError.Protocol):
            buf.write_i32(4)
            _UniffiFfiConverterString.write(value.reason, buf)
        if isinstance(value, DriverError.Tool):
            buf.write_i32(5)
            _UniffiFfiConverterString.write(value.tool, buf)
            _UniffiFfiConverterString.write(value.message, buf)
            _UniffiFfiConverterString.write(value.error_code, buf)
        if isinstance(value, DriverError.Shutdown):
            buf.write_i32(6)






class DriverExecutionMode(enum.Enum):
    """
    Process topology used by this SDK object.
"""

